"""
MKT Christ Commentary — Job chapters 19–21
Run: python3 scripts/zc-christ-job-19-21.py

Ch 19: The Redeemer declaration — v25 already in data from stub; surrounding verses:
    the cry of ḥāmās injustice (v7 → Matt 27:46); the military-siege metaphor pointing
    to Christ besieged by divine wrath (vv6-12 → Gal 3:13); the social abandonment
    pattern (vv13-19 → Isa 53:3); the wish for written testimony (vv23-24); the
    resurrection vision (vv26-27 → 1 Cor 15:20); the sword-warning (vv28-29).
Ch 20: Zophar's retribution theology — every verse applied Christologically: the
    wicked man who receives divine judgment is a shadow of Christ bearing the curse
    in our place; the cobra-venom poison (vv14-16 → Num 21 / John 3:14); the
    divine-warrior weapons (vv23-25 → bearing wrath at Calvary); the two-witness
    universe (v27 → heaven and earth at the cross).
Ch 21: Job's theodicy inversion — each verse connects to the cross as the scandal
    that disrupts retribution theology; the cup of wrath (v20 → Matt 26:39-42);
    death as equalizer broken by resurrection (v26 → 1 Cor 15:20-22); the appeal
    to universal witness (v29 → Acts 2:22 "as you yourselves know").
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "19": {
    "1": "<p>The speech-attribution formula marks Job&rsquo;s speech that contains the Redeemer declaration and the resurrection vision. Christ is the one who ultimately speaks back to every false representation of divine justice &mdash; not merely with words, but with the empty tomb that overturns all accusations of divine injustice. His resurrection is the divine vindication of Job&rsquo;s faith that climaxes in v25.</p>",
    "2": "<p>&ldquo;How long will you torment me and crush my soul with words?&rdquo; Job&rsquo;s anguish under repeated verbal attack anticipates Christ&rsquo;s experience before his accusers &mdash; those who hurled false charges, &ldquo;many false witnesses came forward&rdquo; (Matt 26:60). The soul-crushing weight of false accusation is borne by Christ who was condemned on the basis of twisted testimony (Matt 26:61&ndash;66), bearing the torment of unjust verdict on behalf of all who are wrongly condemned.</p>",
    "3": "<p>&ldquo;Ten times now you have reproached me; you are not ashamed to wrong me.&rdquo; Repeated, shameless reproach is the pattern of Christ&rsquo;s passion week: the mockery at the Sanhedrin (Matt 26:67&ndash;68), before Herod (Luke 23:11), at the cross (Matt 27:39&ndash;44). Those who reproached Christ were not ashamed &mdash; they acted openly, in public, with institutional sanction. He bore the accumulated weight of repeated shaming in order to bear our shame (Heb 12:2: &ldquo;scorning its shame&rdquo;).</p>",
    "4": "<p>&ldquo;Even if I have truly erred, my error rests with me alone.&rdquo; Job insists his sin is his own and does not justify the severity of his treatment. Christ had no error of his own whatsoever &mdash; yet he accepted the error of others as entirely his own: &ldquo;he made him who knew no sin to be sin for us&rdquo; (2 Cor 5:21). The sinless one voluntarily took ownership of all human error, making Job&rsquo;s conditional hypothetical Christ&rsquo;s literal reality.</p>",
    "5": "<p>&ldquo;If you truly exalt yourselves over me and press my disgrace against me as evidence.&rdquo; The pressing of disgrace as legal evidence anticipates the charge of blasphemy leveled against Jesus (Matt 26:65: &ldquo;he has spoken blasphemy! Why do we need any more witnesses?&rdquo;). His words were used as the evidence of his condemnation, just as Job&rsquo;s words are pressed against him. The exaltation of accusers over the righteous sufferer is the pattern of the trial of Christ.</p>",
    "6": "<p>&ldquo;Know that God has overthrown me and thrown his net around me.&rdquo; The divine net around Job is a shadow of Christ&rsquo;s voluntary capture by the divine plan. Christ was not caught &mdash; he surrendered: &ldquo;no one takes my life from me, but I lay it down of my own accord&rdquo; (John 10:18). Yet Gal 3:13 confirms the divine action: &ldquo;Christ redeemed us from the curse of the law by becoming a curse for us.&rdquo; God &ldquo;overthrew&rdquo; him &mdash; struck him as our substitute &mdash; and the net of divine judgment fell on him rather than on us.</p>",
    "7": "<p>A direct anticipation: &ldquo;I shout &lsquo;Injustice!&rsquo; but no one answers; I call for justice but there is no verdict.&rdquo; The unheard cry of the innocent sufferer is the lament at the heart of the passion: Christ&rsquo;s cry of dereliction from the cross, quoting Ps 22:1&ndash;2 (&ldquo;My God, my God, why have you forsaken me? I cried by day but you did not answer&rdquo;) and experiencing precisely what Job describes &mdash; the just one crying out to God with no answer received. He entered the silence so that believers would never face unanswered cries of abandonment (Rom 8:35&ndash;39).</p>",
    "8": "<p>&ldquo;He has blocked my way so I cannot pass; he has set darkness over my paths.&rdquo; Christ entered the darkest blocked way &mdash; death itself &mdash; and broke through. The darkness at the crucifixion was literal (Matt 27:45: &ldquo;from noon until three in the afternoon darkness came over all the land&rdquo;) and theological: the darkness of divine judgment. He emerged from that darkness in resurrection, becoming himself the path that is now unblocked (John 14:6: &ldquo;I am the way&rdquo;).</p>",
    "9": "<p>&ldquo;He has stripped me of my honor and taken the crown from my head.&rdquo; The stripping of honor and crown is enacted in the passion narrative: the soldiers stripped Christ of his clothing (Matt 27:28), put a crown of thorns on his head in mockery (Matt 27:29), and then stripped the mock robe away. The stripping of honor he endured became the garment of righteousness for believers (Rev 3:18: &ldquo;buy white clothes to wear, so you can cover your shameful nakedness&rdquo;).</p>",
    "10": "<p>&ldquo;He has broken me down on every side and I am gone; he has pulled up my hope like a tree.&rdquo; The uprooting of hope is precisely what the cross appeared to be &mdash; the disciples who &ldquo;had hoped that he was the one who was going to redeem Israel&rdquo; (Luke 24:21) used the past tense. But Christ, uprooted from life, was replanted in resurrection: John 12:24 (&ldquo;unless a kernel of wheat falls to the ground and dies, it remains only a single seed; but if it dies, it produces many seeds&rdquo;). The pulled-up tree sprouts again (Job 14:7&ndash;9).</p>",
    "11": "<p>&ldquo;He has kindled his wrath against me and counted me as one of his enemies.&rdquo; The divine counting of Christ as an enemy of God &mdash; bearing the wrath of divine judgment &mdash; is the theology of substitutionary atonement. Isa 53:10: &ldquo;yet it was the LORD&rsquo;s will to crush him and cause him to suffer.&rdquo; 2 Cor 5:21: &ldquo;God made him who had no sin to be sin for us.&rdquo; The wrath kindled against Christ was the wrath due to all who were genuinely God&rsquo;s enemies (Rom 5:10: &ldquo;while we were God&rsquo;s enemies, we were reconciled through the death of his Son&rdquo;).</p>",
    "12": "<p>&ldquo;His troops advance together; they heap up siege ramps against me and encamp around my tent.&rdquo; The military siege imagery points to Christ surrounded in Gethsemane: &ldquo;a large crowd armed with swords and clubs came from the chief priests and the elders of the people&rdquo; (Matt 26:47). But more profoundly, the divine wrath that Christ bore was like a cosmic siege: the full weight of divine judgment advancing against him so it would not advance against those he was redeeming (Gal 3:13).</p>",
    "13": "<p>&ldquo;He has put my brothers far from me, and those who knew me have become wholly estranged.&rdquo; The estrangement of family and friends is the pattern of Christ&rsquo;s passion: &ldquo;they all deserted him and fled&rdquo; (Matt 26:56); Peter&rsquo;s denial (Matt 26:69&ndash;75); the disciples hiding behind locked doors (John 20:19). Yet from the cross he established new family bonds (John 19:26&ndash;27), and in his resurrection he called the deserters &ldquo;my brothers&rdquo; (Matt 28:10; John 20:17).</p>",
    "14": "<p>&ldquo;My relatives have failed me, and my familiar friends have forgotten me.&rdquo; Abandonment by familiar friends is a central feature of Ps 22 (&ldquo;all who see me mock me; they hurl insults, shaking their heads,&rdquo; v7), which Christ quoted from the cross. But Christ&rsquo;s purpose was precisely to ensure that believers would never face this final abandonment &mdash; Heb 13:5 (&ldquo;I will never leave you; I will never forsake you&rdquo;) is the promise that his abandonment secured.</p>",
    "15": "<p>&ldquo;Those living in my house and my female servants count me as a stranger.&rdquo; Christ came to what was his own household and &ldquo;his own did not receive him&rdquo; (John 1:11). He was counted a stranger in his own creation: born in a stable because &ldquo;there was no room for them in the inn&rdquo; (Luke 2:7); rejected in his hometown (Luke 4:24: &ldquo;no prophet is accepted in his hometown&rdquo;). The household&rsquo;s rejection of Job anticipates the world&rsquo;s rejection of the one through whom it was made.</p>",
    "16": "<p>&ldquo;I called my servant, but he gave me no answer; I had to beg him with my own mouth.&rdquo; The master reduced to begging serves as an inversion type of the incarnation. Christ, the Lord of all, &ldquo;did not come to be served, but to serve&rdquo; (Matt 20:28). He who commands the universe became one who serves, washes feet (John 13:4&ndash;5), and asks for a drink of water from a Samaritan woman (John 4:7) &mdash; the full voluntary humiliation of the one who was owed service by all.</p>",
    "17": "<p>&ldquo;My breath is repulsive to my wife; I am loathsome to the sons of my own body.&rdquo; The physical and relational repulsiveness of the suffering Job points to Isa 53:2&ndash;3: &ldquo;he had no beauty or majesty to attract us to him&hellip; he was despised and rejected by mankind&rdquo;; &ldquo;like one from whom people hide their faces he was despised.&rdquo; Christ became repulsive in the eyes of those who witnessed the crucifixion (Isa 52:14: &ldquo;his appearance was so disfigured beyond that of any human being&rdquo;) so that we would not be loathsome before God.</p>",
    "18": "<p>&ldquo;Even young children despise me; when I stand up they speak against me.&rdquo; The universal rejection &mdash; even by children &mdash; reflects the breadth of human rejection of Christ. Yet Luke records children crying &ldquo;Hosanna to the Son of David&rdquo; in the temple (Matt 21:15), and Jesus blessed the children others tried to keep away (Matt 19:14). He identified with the rejected even as he was rejected, making the despised into the honored.</p>",
    "19": "<p>&ldquo;All my closest companions abhor me; those I loved have turned against me.&rdquo; Ps 55:12&ndash;14 describes the same experience with prophetic precision: &ldquo;if an enemy were insulting me, I could endure it&hellip; but it is you, a man like myself, my companion, my close friend.&rdquo; Christ explicitly fulfills this Psalm at the Last Supper: &ldquo;he who shares my bread has lifted up his heel against me&rdquo; (John 13:18, quoting Ps 41:9). The beloved companion who turned against Job is the pattern of Judas.</p>",
    "20": "<p>&ldquo;My bones cling to my skin and flesh; I have escaped with only the skin of my teeth.&rdquo; The extreme bodily degradation of Job describes the condition Christ entered at the cross: extreme thirst (&ldquo;I am thirsty,&rdquo; John 19:28, fulfilling Ps 22:15: &ldquo;my strength is dried up like a potsherd; and my tongue sticks to the roof of my mouth&rdquo;); bones not broken but exposed to view (Ps 22:17: &ldquo;I can count all my bones; people stare and gloat over me&rdquo;; John 19:36 &ldquo;not one of his bones will be broken&rdquo;).</p>",
    "21": "<p>&ldquo;Have pity on me, have pity on me, O my friends, for the hand of God has struck me.&rdquo; The double appeal for pity is echoed in Lam 1:12: &ldquo;is it nothing to you, all who pass by? Look around and see: is any suffering like my suffering?&rdquo; &mdash; a verse traditionally applied to Christ&rsquo;s passion. The &ldquo;hand of God&rdquo; that struck Job is the hand that struck the Shepherd: &ldquo;strike the shepherd, and the sheep will be scattered&rdquo; (Zech 13:7, quoted in Matt 26:31), the hand of divine wrath that fell on Christ for our sake.</p>",
    "22": "<p>&ldquo;Why do you pursue me like God, and are not satisfied with my flesh?&rdquo; The accusers who pursue like God anticipate the religious leaders at the cross who joined in and were not satisfied until life was extinguished: &ldquo;come down from the cross, if you are the Son of God&rdquo; (Matt 27:40). Yet even their insatiable pursuit served the divine purpose: &ldquo;this man was handed over to you by God&rsquo;s deliberate plan and foreknowledge; and you, with the help of wicked men, put him to death by nailing him to the cross&rdquo; (Acts 2:23).</p>",
    "23": "<p>&ldquo;O that my words were written down! O that they were inscribed in a book!&rdquo; Job&rsquo;s wish for a permanent written record is fulfilled beyond expectation: his words are written down in Scripture and have been read for three millennia. More profoundly, Christ is himself the Word inscribed &mdash; &ldquo;the Word became flesh and made his dwelling among us&rdquo; (John 1:14). And the record of all charges against believers has been permanently canceled: &ldquo;nailing it to the cross&rdquo; (Col 2:14) &mdash; the final written record, erased.</p>",
    "24": "<p>&ldquo;That with an iron pen and lead they were cut into the rock forever!&rdquo; The desire for the most permanent possible record anticipates the written titulus crucis &mdash; the charge nailed to the cross &mdash; and more deeply, the indestructible nature of Christ&rsquo;s saving work. Heb 13:8: &ldquo;Jesus Christ is the same yesterday, today and forever.&rdquo; Rev 20:12: the books that cannot be erased. And the names of believers written in the Lamb&rsquo;s book of life (Rev 21:27) &mdash; the permanent record that outlasts all else.</p>",
    "26": "<p>&ldquo;And after my skin is thus destroyed, yet from within my flesh I shall see God.&rdquo; The bodily resurrection vision: Christ&rsquo;s resurrection body was the first fulfillment &mdash; he appeared to Mary (John 20:14&ndash;17), to the disciples (John 20:19&ndash;29), to 500 at once (1 Cor 15:6). His risen body, though transformed, was physically recognizable (Luke 24:39&ndash;43: &ldquo;touch me and see; a ghost does not have flesh and bones, as you see I have&rdquo;). The &ldquo;from within my flesh&rdquo; is the same bodily resurrection Paul defends in 1 Cor 15:35&ndash;49.</p>",
    "27": "<p>&ldquo;Whom I myself shall see, and my own eyes shall behold &mdash; not a stranger&rsquo;s eyes. My heart fails within me with longing.&rdquo; The intensely personal vision of God that Job longs for is the beatific vision that Christ makes possible. John 17:24: &ldquo;Father, I want those you have given me to be with me where I am, and to see my glory.&rdquo; 1 John 3:2: &ldquo;when Christ appears, we shall be like him, for we shall see him as he is.&rdquo; The longing that makes Job&rsquo;s heart fail is the longing for the personal encounter that Christ embodies and mediates.</p>",
    "28": "<p>&ldquo;If you say, &lsquo;Why are we still pursuing him?&rsquo; when the root of the trouble lies within him.&rdquo; Job predicts the friends will eventually abandon their pursuit. The parallel in Christ&rsquo;s trial: after the resurrection, the Jewish leaders no longer &ldquo;pursued&rdquo; the case &mdash; they could not. The empty tomb ended the legal case (Acts 4:21: &ldquo;they could not decide how to punish them, because all the people were praising God for what had happened&rdquo;). The &ldquo;root of the matter&rdquo; was not in Job; the root of all human sin was dealt with in Christ.</p>",
    "29": "<p>&ldquo;Fear the sword, for wrath brings the sword&rsquo;s punishment, so that you may know there is indeed a judgment.&rdquo; The warning of coming judgment anticipates the final judgment that Christ will execute. John 5:22: &ldquo;the Father judges no one, but has entrusted all judgment to the Son.&rdquo; Those who falsely accused Job will face judgment; those who falsely condemned Christ will face judgment (Rev 19:11&ndash;15: &ldquo;with justice he judges and wages war&rdquo;). The sword Job warns about is the sword of the divine Word (Rev 19:15: &ldquo;coming out of his mouth is a sharp sword&rdquo;).</p>"
  },
  "20": {
    "1": "<p>Zophar&rsquo;s speech of retribution theology is the Old Testament&rsquo;s most systematic statement of the principle that Christ bore in order to redeem those it condemned. The entire speech functions as a description of divine curse upon wickedness &mdash; a curse that Paul says Christ absorbed: &ldquo;Christ redeemed us from the curse of the law by becoming a curse for us&rdquo; (Gal 3:13). Zophar&rsquo;s theology is not entirely wrong; it just failed to account for the substitutionary resolution.</p>",
    "2": "<p>&ldquo;Therefore my thoughts push me to answer; I feel urgency within me.&rdquo; The urgency to defend divine justice is a legitimate theological impulse. Christ came to &ldquo;fulfill&rdquo; the law and the prophets, not abolish them (Matt 5:17) &mdash; that is, to enact divine justice in full, not to dismiss it. The urgency Zophar feels to defend divine retributive justice is the urgency that the cross satisfies: God is just and the one who justifies (Rom 3:26).</p>",
    "3": "<p>Zophar&rsquo;s claim to possess special understanding beyond ordinary human grasp anticipates Paul&rsquo;s description of the mystery of Christ hidden and then revealed: &ldquo;the mystery hidden for ages&rdquo; (Col 1:26&ndash;27) was beyond the grasp of even the wisest wisdom teachers until the Spirit revealed it. What Zophar &ldquo;understands&rdquo; is the retribution pattern; what was hidden was the substitutionary resolution of that pattern in Christ.</p>",
    "4": "<p>&ldquo;From of old, since man was set upon the earth&rdquo; &mdash; Zophar appeals to the primordial order. The primordial order includes the curse on sin from Gen 3; the creation order does embed a retributive pattern. But Paul argues from the same primordial order to show that God had planned a resolution from before creation: &ldquo;chosen in him before the creation of the world&rdquo; (Eph 1:4). The ancient pattern of retribution was always destined to be resolved by the ancient plan of redemption.</p>",
    "5": "<p>&ldquo;The triumph of the wicked is short, and the joy of the godless lasts but a moment.&rdquo; Applied to Christ: the apparent triumph of those who crucified him was indeed short. By Sunday morning the triumphant parties &mdash; the religious leaders who had gained their verdict, Pilate who had maintained order, death itself &mdash; found their triumph overturned. Paul in 1 Cor 15:55: &ldquo;where, O death, is your victory? Where, O death, is your sting?&rdquo; The triumph lasted three days; the victory of resurrection is eternal.</p>",
    "6": "<p>&ldquo;Though his greatness mounts to the heavens and his head reaches the clouds.&rdquo; The hubristic overreach into the divine sphere finds its antithesis in the incarnation: Christ descended from heaven rather than ascending to it (John 3:13: &ldquo;no one has ever gone into heaven except the one who came from heaven &mdash; the Son of Man&rdquo;). The one who had genuine divine height chose genuine human humility (Phil 2:6&ndash;8), reversing the pride-pattern that Zophar describes as the mark of the doomed wicked.</p>",
    "7": "<p>&ldquo;He will perish forever like his own dung; those who saw him will say, &lsquo;Where is he?&rsquo;&rdquo; The &ldquo;where is he?&rdquo; of the vanished wicked becomes the &ldquo;where is he?&rdquo; of the empty tomb. The guards said &ldquo;where is he?&rdquo; when they found the tomb empty; Mary said &ldquo;where have you taken him?&rdquo; (John 20:13,15). But the answer is the opposite of Zophar&rsquo;s intended meaning: &ldquo;he is not here; he has risen!&rdquo; (Matt 28:6). The &ldquo;where is he&rdquo; of vanishment becomes the &ldquo;where is he&rdquo; of resurrection-astonishment.</p>",
    "8": "<p>&ldquo;He flies away like a dream and cannot be found.&rdquo; The vanishment of the wicked anticipates the resurrection appearances where Christ appeared and disappeared at will: &ldquo;while he was eating with them, he disappeared from their sight&rdquo; (Luke 24:31); appearing through locked doors (John 20:19,26). He who was expected to be permanently vanished by death cannot be found in the tomb but is repeatedly found alive &mdash; the reversal of the dream-vanishment pattern.</p>",
    "9": "<p>&ldquo;The eye that saw him will see him no more; his own place will no longer recognize him.&rdquo; The disciples on the road to Emmaus were kept from recognizing Christ (Luke 24:16: &ldquo;they were kept from recognizing him&rdquo;). The empty tomb meant his former place no longer contained him. But then recognition came (Luke 24:31: &ldquo;their eyes were opened and they recognized him&rdquo;) &mdash; the place that no longer recognized the dead one now recognizes the Risen One.</p>",
    "10": "<p>&ldquo;His children will seek favor from the poor, and his hands will give back their wealth.&rdquo; The reversal &mdash; the formerly wealthy reduced to dependence on the poor &mdash; is enacted in Christ&rsquo;s incarnation: the rich one became poor so that through his poverty we might become rich (2 Cor 8:9: &ldquo;though he was rich, yet for your sake he became poor, so that you through his poverty might become rich&rdquo;). The voluntary poverty of the incarnation is the positive counterpart to Zophar&rsquo;s forced poverty of the wicked.</p>",
    "11": "<p>&ldquo;His bones are full of the sins of his youth; they will lie down with him in the dust.&rdquo; Christ&rsquo;s bones held no sin of his own &mdash; yet he bore ours. His bones were deliberately preserved intact at the crucifixion (John 19:36, fulfilling Ps 34:20: &ldquo;he protects all his bones, not one of them will be broken&rdquo;). The sin that should have lodged in human bones was laid on him instead; he went down into the dust carrying our sins, and rose leaving them buried.</p>",
    "12": "<p>&ldquo;Though evil is sweet in his mouth and he hides it under his tongue.&rdquo; The hiding of evil contrasts with Christ who had nothing to hide: &ldquo;which one of you convicts me of sin?&rdquo; (John 8:46). Yet he voluntarily took on what was hidden &mdash; he bore the secret sins, the private wickedness, the hidden darkness of all humanity (Matt 6:4,6,18: &ldquo;your Father who sees what is done in secret will reward you&rdquo;). He who was transparent bore the opacity of all human sin.</p>",
    "13": "<p>&ldquo;Though he spares it and will not let it go, but keeps it lodged in his mouth.&rdquo; The retention of evil that leads to death is what Christ drank to the dregs. The cup he prayed to avoid (Matt 26:39: &ldquo;let this cup pass from me&rdquo;) contained the concentrated evil of human sin; he did not spit it out but drank it fully: &ldquo;my Father, if this cup cannot pass unless I drink it, may your will be done&rdquo; (Matt 26:42). He consumed what others retained, so that they would not be consumed by it.</p>",
    "14": "<p>&ldquo;Yet his food turns in his stomach; it becomes cobra venom inside him.&rdquo; The transformation of sweetness into poison recalls the bronze serpent in the wilderness: Num 21:6&ndash;9, where serpent venom was the judgment on sin. Christ explicitly connects himself to this scene: &ldquo;just as Moses lifted up the snake in the desert, so the Son of Man must be lifted up, that everyone who believes in him may have eternal life&rdquo; (John 3:14&ndash;15). He absorbed the serpent&rsquo;s poison on the cross so that those who look to him are healed.</p>",
    "15": "<p>&ldquo;He swallowed wealth down, and will vomit it up again; God will expel it from his belly.&rdquo; The divine expulsion of unjust wealth points to the resurrection as the expulsion of death&rsquo;s claim: death swallowed Christ (1 Cor 15:54: &ldquo;death has been swallowed up in victory&rdquo;) and then could not keep him. Hos 13:14 (quoted in 1 Cor 15:55): &ldquo;I will redeem them from death. Where, O death, are your plagues? Where, O grave, is your destruction?&rdquo; Death swallowed him and was forced to give him up.</p>",
    "16": "<p>&ldquo;He will suck the venom of cobras; the tongue of the viper will kill him.&rdquo; The serpent&rsquo;s venom as divine judgment connects to the Edenic curse (Gen 3:15: &ldquo;he will crush your head, and you will strike his heel&rdquo;). Christ bore the serpent&rsquo;s strike &mdash; the viper&rsquo;s tongue that kills. But the crushing of the serpent&rsquo;s head is the resurrection defeat of Satan: Heb 2:14 (&ldquo;by his death he might destroy him who holds the power of death &mdash; that is, the devil&rdquo;). He was struck by the serpent so that the serpent would be crushed.</p>",
    "17": "<p>&ldquo;He will not look on the rivers, the streams, the brooks flowing with honey and butter.&rdquo; The wicked man who will not taste the promised abundance contrasts with Christ who both is and provides living water: &ldquo;whoever drinks the water I give them will never thirst again&rdquo; (John 4:14); &ldquo;rivers of living water will flow from within them&rdquo; (John 7:38). He was thirsty on the cross (John 19:28) so that all who come to him would never thirst.</p>",
    "18": "<p>&ldquo;He must restore the fruits of his labor without consuming them.&rdquo; Christ&rsquo;s labor was entirely for others: he came &ldquo;not to be served, but to serve, and to give his life as a ransom for many&rdquo; (Matt 20:28). The fruits of his labor &mdash; justification, sanctification, glorification &mdash; are all given away: &ldquo;freely you have received; freely give&rdquo; (Matt 10:8). He labored and others eat; he planted and others taste the fruit (John 4:37&ndash;38: &ldquo;others have done the hard work, and you have reaped the benefits&rdquo;).</p>",
    "19": "<p>&ldquo;For he oppressed and abandoned the poor; he seized a house he did not build.&rdquo; Christ did the opposite: he served the poor (Luke 4:18: &ldquo;the Spirit of the Lord is on me, because he has anointed me to proclaim good news to the poor&rdquo;), championed the abandoned (the widow, the orphan, the outcast), and built a house not for himself but for others (&ldquo;I am going there to prepare a place for you,&rdquo; John 14:2). His entire ministry is the reversal of every social injustice Zophar catalogues.</p>",
    "20": "<p>&ldquo;He will not feel peace within; he will retain nothing of what he desired.&rdquo; Christ is the source of peace precisely because he himself entered the absence of peace in Gethsemane and at the cross: John 14:27 (&ldquo;peace I leave with you; my peace I give you. I do not give to you as the world gives&rdquo;). His peace in resurrection (&ldquo;peace be with you,&rdquo; John 20:19,21,26) comes after passing through the storm of divine judgment &mdash; peace given out of a profound personal experience of its absence.</p>",
    "21": "<p>&ldquo;None of his food is left; therefore no one will inherit his property.&rdquo; The wicked man&rsquo;s total consumption leaving nothing for inheritance contrasts with Christ whose inheritance multiplies: Ps 2:8 (&ldquo;ask me, and I will make the nations your inheritance, the ends of the earth your possession&rdquo;); Rom 8:17 (believers are &ldquo;heirs of God and co-heirs with Christ&rdquo;). He died leaving not desolation but an inheritance inexhaustible for all who receive it.</p>",
    "22": "<p>&ldquo;In the very fullness of his plenty he will be in distress.&rdquo; The reversal of abundance into distress anticipates Christ&rsquo;s voluntary entry into distress: Phil 4:11&ndash;13 (&ldquo;I have learned to be content whatever the circumstances&rdquo; &mdash; the opposite of this &ldquo;distress in fullness&rdquo;). Christ, who was the fullness of divinity (Col 2:9: &ldquo;in Christ all the fullness of the Deity lives in bodily form&rdquo;), entered the distress of the cross without being destroyed by it.</p>",
    "23": "<p>&ldquo;When he is set to fill his belly, God will hurl his fierce wrath upon him.&rdquo; The divine wrath poured out at the moment of intended satisfaction is the theology of the cross: Christ at his &ldquo;hour&rdquo; &mdash; the moment appointed for his glory &mdash; received the cup of divine wrath. The Last Supper of bread and wine was immediately followed by Gethsemane and the cross. He was set to fill others with his body and blood; what fell on him was the fierce wrath that would otherwise have fallen on them.</p>",
    "24": "<p>&ldquo;He flees from the iron weapon, and the bronze bow strikes him through.&rdquo; The inescapability of divine judgment &mdash; fleeing one weapon only to be struck by another &mdash; is the inescapability that Christ voluntarily embraced. He did not flee: &ldquo;do you think I cannot call on my Father, and he will at once put at my disposal more than twelve legions of angels? But how then would the Scriptures be fulfilled?&rdquo; (Matt 26:53&ndash;54). He stood still, let the weapons fall, and thereby absorbed the inescapable judgment so others could escape.</p>",
    "25": "<p>&ldquo;The arrow is drawn; it passes through his body; the shining blade comes out through his gall; terrors overwhelm him.&rdquo; The physical description of being struck through anticipates the soldier&rsquo;s lance thrust into Christ&rsquo;s side (John 19:34: &ldquo;one of the soldiers pierced Jesus&rsquo; side with a spear, bringing a sudden flow of blood and water&rdquo;). The blade that came through Christ&rsquo;s body confirmed his death &mdash; and the blood and water that flowed became the source of sacramental life for the church.</p>",
    "26": "<p>&ldquo;All darkness is kept in store for his treasures; a fire not fanned by wind shall consume him.&rdquo; The stored-up darkness &mdash; darkness associated with divine judgment &mdash; fell on Christ at the cross: &ldquo;from noon until three in the afternoon darkness came over all the land&rdquo; (Matt 27:45). The spontaneous fire of divine judgment consuming the wicked becomes the fire of divine love consuming the sin that Christ bore. He emerged from the darkness in resurrection, and now light, not darkness, is kept in store for his treasures.</p>",
    "27": "<p>&ldquo;The heavens will expose his guilt, and the earth will rise up against him.&rdquo; Heaven and earth as legal witnesses against the condemned: at the cross, the opposite occurred for the convicted but innocent Christ. The centurion who watched said &ldquo;surely this man was the Son of God!&rdquo; (Mark 15:39) &mdash; heaven witnessed on his behalf. The earth shook (Matt 27:51: &ldquo;the earth shook, the rocks split&rdquo;) &mdash; not in condemnation but in cosmic response to the death of the Creator. Heaven and earth testified to his identity, not his guilt.</p>",
    "28": "<p>&ldquo;The produce of his house will depart; his possessions will pour away in the day of his anger.&rdquo; On the day of Christ&rsquo;s death, the temple curtain was torn from top to bottom (Matt 27:51) &mdash; the possessions of the old sacrificial system poured away. But this was not loss; it was fulfillment: the &ldquo;house&rdquo; of the old covenant gave way to the better house of his body and the Spirit&rsquo;s temple (1 Cor 3:16; 6:19; John 2:21: &ldquo;the temple he had spoken of was his body&rdquo;).</p>",
    "29": "<p>&ldquo;This is the portion of the wicked man from God &mdash; the heritage decreed for him by God.&rdquo; The divinely decreed heritage of wicked men is what Christ voluntarily received in their place. Gal 3:13: &ldquo;Christ redeemed us from the curse of the law by becoming a curse for us, for it is written: &lsquo;Cursed is everyone who is hung on a pole.&rsquo;&rdquo; He accepted the heritage decreed for the wicked so that the wicked might receive the heritage of the righteous &mdash; &ldquo;an inheritance that can never perish, spoil or fade&rdquo; (1 Pet 1:4).</p>"
  },
  "21": {
    "1": "<p>Job&rsquo;s counter-speech &mdash; the most systematic empirical challenge to retribution theology in the OT &mdash; is itself a forward-pointer to the cross as the ultimate disruption of the retribution system. The crucifixion of the sinless Son of God is the definitive empirical datum that breaks the equation of suffering = wickedness: here the perfectly righteous One suffers maximally, permanently refuting the retribution principle as an absolute rule.</p>",
    "2": "<p>&ldquo;Listen carefully to what I say; let this be your consolation.&rdquo; Job ironically offers his words as the only real comfort available. Christ is the true Comforter and Consolation: Simeon held the infant Jesus as &ldquo;the consolation of Israel&rdquo; (Luke 2:25). John 16:33: &ldquo;in this world you will have trouble. But take heart! I have overcome the world.&rdquo; The consolation that Job&rsquo;s friends could not provide, Christ delivers through his death and resurrection.</p>",
    "3": "<p>&ldquo;Bear with me so I may speak; and after I have spoken, mock away.&rdquo; Christ made his definitive speech through the cross and resurrection, after which the mockers have nothing more to say. The mockers at the cross invited him to come down; he did not come down during crucifixion &mdash; but he came out of the tomb on the third day, and since then the mockers&rsquo; &ldquo;mock away&rdquo; invitation has been taken up in a different way (1 Cor 4:10&ndash;13: &ldquo;we are fools for Christ&rdquo;).</p>",
    "4": "<p>&ldquo;As for me, is my complaint directed to man? Why then should I not be impatient?&rdquo; Job insists his complaint is directed to God, not to humans. Christ&rsquo;s cry of dereliction (Matt 27:46) was likewise directed to the Father, not to the crowd. His complaint &mdash; &ldquo;why have you forsaken me?&rdquo; &mdash; was a divine-court complaint, not a human audience address. The Son who knew perfect communion with the Father experienced its rupture on our behalf.</p>",
    "5": "<p>&ldquo;Look at me and be appalled; lay your hand over your mouth.&rdquo; The demand to look and be appalled anticipates Isa 52:14 (fulfilled at the cross): &ldquo;many were appalled at him &mdash; his appearance was so disfigured beyond that of any human being.&rdquo; Christ himself demanded the same awe-struck silence from his executioners and witnesses, and his resurrection has silenced every counter-argument: &ldquo;who will bring any charge against those whom God has chosen? It is God who justifies&rdquo; (Rom 8:33).</p>",
    "6": "<p>&ldquo;Even when I think of it I am troubled, and shuddering seizes my flesh.&rdquo; The visceral dread of confronting unjust suffering anticipates Gethsemane: Christ &ldquo;began to be deeply distressed and troubled&rdquo; (Mark 14:33); &ldquo;my soul is overwhelmed with sorrow to the point of death&rdquo; (Mark 14:34); his sweat &ldquo;was like drops of blood falling to the ground&rdquo; (Luke 22:44). He experienced fully the shuddering that the prospect of bearing human sin caused in his sinless humanity.</p>",
    "7": "<p>&ldquo;Why do the wicked go on living, grow old, and even grow mighty in power?&rdquo; The theodicy question reaches its NT answer in Rom 2:4&ndash;5: God&rsquo;s patience with the wicked is not injustice but &ldquo;kindness, forbearance, and patience&rdquo; that is &ldquo;intended to lead you to repentance.&rdquo; Christ bears the wicked&rsquo;s prosperity: &ldquo;he causes his sun to rise on the evil and the good, and sends rain on the righteous and the unrighteous&rdquo; (Matt 5:45). The ultimate answer to Job&rsquo;s question is eschatological: the final judgment (Rev 20:11&ndash;15).</p>",
    "8": "<p>&ldquo;Their children are established around them, and their offspring before their eyes.&rdquo; The prosperity of the wicked&rsquo;s household echoes what Job himself lost. Christ promised a new household for all who lose family for his sake: &ldquo;no one who has left home or brothers or sisters or mother or father or children or fields for me and the gospel will fail to receive a hundred times as much in this present age&rdquo; (Mark 10:29&ndash;30). The family that remains intact for the wicked is vastly exceeded by the new family Christ constitutes.</p>",
    "9": "<p>&ldquo;Their houses are safe from fear; the rod of God is not upon them.&rdquo; The temporary absence of divine discipline for the wicked is contrasted with the consistent discipline of the righteous (Heb 12:6: &ldquo;the Lord disciplines the one he loves&rdquo;). Christ bore the rod of God fully and permanently on behalf of believers so that their discipline is the discipline of a beloved child, not the wrath of a judge. Isa 53:5: &ldquo;the punishment that brought us peace was on him.&rdquo;</p>",
    "10": "<p>&ldquo;Their bull breeds without fail; their cow calves and does not miscarry.&rdquo; The fertility and productivity of the wicked&rsquo;s household points forward to the abundant life Christ promised: &ldquo;I have come that they may have life, and have it to the full&rdquo; (John 10:10). The fertility that belongs to the wicked by apparent accident belongs to believers by covenant promise &mdash; spiritual fruitfulness that multiplies thirty, sixty, and a hundredfold (Matt 13:23).</p>",
    "11": "<p>&ldquo;Their little ones run out like a flock, and their children dance.&rdquo; The dancing children of the wicked are answered by Christ&rsquo;s welcome of children: &ldquo;let the little children come to me, and do not hinder them, for the kingdom of heaven belongs to such as these&rdquo; (Matt 19:14). And by the eschatological promise of Zech 8:5 (&ldquo;the city streets will be filled with boys and girls playing there&rdquo;) &mdash; a joy that belongs to the redeemed community, not merely to those who happen to prosper now.</p>",
    "12": "<p>&ldquo;They take up timbrel and harp and rejoice at the sound of the flute.&rdquo; Musical celebration belonging to the wicked is the present-age irony that Christ will ultimately resolve. Luke 15:25 uses the same image: when the father celebrates the prodigal&rsquo;s return, &ldquo;he heard music and dancing.&rdquo; The feast and music in the father&rsquo;s house &mdash; which the elder brother resents &mdash; are the celebration of the Kingdom that Christ inaugurates for all who return.</p>",
    "13": "<p>&ldquo;They spend their days in prosperity and go down to Sheol in an instant.&rdquo; The peaceful death of the wicked is answered by Christ who descended to Sheol but did not remain: Acts 2:27 (quoting Ps 16:10): &ldquo;you will not abandon me to the realm of the dead, nor will you let your faithful one see decay.&rdquo; He went to Sheol briefly and returned, making his return the guarantee of resurrection for all who believe (1 Cor 15:20: &ldquo;the firstfruits of those who have fallen asleep&rdquo;).</p>",
    "14": "<p>&ldquo;Yet they say to God, &lsquo;Leave us alone; we have no desire to know your ways.&rsquo;&rdquo; The rejection of God&rsquo;s ways by the wicked is the condition Christ came to heal. He came precisely to the ones who wanted to be left alone (Luke 15:1&ndash;7: seeking the lost sheep who did not seek him). His incarnation is the divine refusal to leave humanity alone: John 3:16 (&ldquo;for God so loved the world that he gave his one and only Son&rdquo;). Even those who say &ldquo;leave us alone&rdquo; are pursued by the hound of heaven.</p>",
    "15": "<p>&ldquo;Who is the Almighty that we should serve him? What do we gain by praying to him?&rdquo; This is the voice of practical atheism that the cross addresses definitively. The gain from praying to him is everything: &ldquo;he who did not spare his own Son, but gave him up for us all &mdash; how will he not also, along with him, graciously give us all things?&rdquo; (Rom 8:32). Christ&rsquo;s cross is the answer to the transactional objection: God did not spare his own Son; the gain of praying to such a God is incalculable.</p>",
    "16": "<p>&ldquo;Their prosperity is not in their own hand &mdash; the counsel of the wicked I keep far from me.&rdquo; Job&rsquo;s distancing from the wicked&rsquo;s worldview is what believers are called to: &ldquo;do not follow the counsel of the wicked&rdquo; (Ps 1:1). Christ kept entirely free from the wicked&rsquo;s counsel: &ldquo;he has done no violence, nor was any deceit in his mouth&rdquo; (Isa 53:9). His keeping entirely separate from the counsel of the wicked is the ground of his capacity to be our substitute.</p>",
    "17": "<p>&ldquo;How often is the lamp of the wicked actually extinguished?&rdquo; The rhetorical statistical challenge to retribution theology anticipates the patience of God described in 2 Pet 3:9: &ldquo;the Lord is not slow in keeping his promise, as some understand slowness. Instead he is patient with you, not wanting anyone to perish, but everyone to come to repentance.&rdquo; The lamp of the wicked is not immediately extinguished &mdash; but the day is coming when all darkness is permanently ended (Rev 22:5: &ldquo;there will be no more night&rdquo;).</p>",
    "18": "<p>&ldquo;They are as straw before the wind, and chaff swept away by the tempest.&rdquo; The wind and fire of eschatological judgment that this verse envisions are the judgment that Christ absorbed at the cross (Matt 3:12: John the Baptist&rsquo;s description of Christ as the one with a &ldquo;winnowing fork in his hand, clearing his threshing floor&rdquo; &mdash; Christ both performs the final judgment and bore its fire in advance on the cross). The chaff swept away in wrath; the wheat gathered in grace.</p>",
    "19": "<p>&ldquo;You say God stores up punishment for his children; God repays the man himself and he will know it.&rdquo; Job&rsquo;s demand for immediate, personal accountability anticipates the final judgment where each person stands before Christ (2 Cor 5:10: &ldquo;we must all appear before the judgment seat of Christ, so that each of us may receive what is due us&rdquo;). But before that judgment, Christ has borne the punishment himself, enabling justification: &ldquo;since we have been justified through faith, we have peace with God through our Lord Jesus Christ&rdquo; (Rom 5:1).</p>",
    "20": "<p>A direct anticipation: &ldquo;let his own eyes see his destruction; let him drink of the wrath of the Almighty.&rdquo; The cup of the Almighty&rsquo;s wrath is precisely what Christ prayed to avoid in Gethsemane and then voluntarily drank: &ldquo;my Father, if it is not possible for this cup to be taken away unless I drink it, may your will be done&rdquo; (Matt 26:42). He drank it to the dregs on behalf of those who otherwise would have drunk it themselves. The cup of wrath became, through his substitution, the cup of the new covenant (Luke 22:20).</p>",
    "21": "<p>&ldquo;For what pleasure does he take in his house after him, when the number of his months is severed?&rdquo; Christ did not merely leave a house behind him; he prepared one for others: &ldquo;I am going there to prepare a place for you... I will come back and take you to be with me&rdquo; (John 14:2&ndash;3). His death did not sever his months in a final way; it was the door to his resurrection existence in which he continues to build, intercede, and prepare for those who follow him.</p>",
    "22": "<p>&ldquo;Will anyone teach God knowledge? He is the one who judges those on high.&rdquo; The divine transcendence above human instruction is the very attribute that makes God&rsquo;s self-revelation in Christ all the more astonishing: the one who judges those on high became teachable in human form (Luke 2:52: &ldquo;Jesus grew in wisdom and stature&rdquo;; Heb 5:8: &ldquo;though he was the Son, he learned obedience from what he suffered&rdquo;). The one who cannot be taught accepted the limits of the teachable human creature.</p>",
    "23": "<p>&ldquo;One person dies in full vigor, completely at ease and secure.&rdquo; Christ&rsquo;s death was the opposite of this: he died in agony, stripped of security, bearing the full weight of divine judgment. Yet his death was also the death of the innocent, the strong dying for the weak: Rom 5:6 (&ldquo;at just the right time, when we were still powerless, Christ died for the ungodly&rdquo;). The one who could have died in vigor chose to die in weakness so that the weak might receive his vigor.</p>",
    "24": "<p>&ldquo;His sides full of milk and his bones saturated with marrow.&rdquo; The picture of robust physical wholeness is what Christ&rsquo;s resurrection body will restore to believers. Phil 3:21: &ldquo;he will transform our lowly bodies so that they will be like his glorious body.&rdquo; The physical richness that marks the blessed person in ANE thought becomes, in Christ, the eschatological promise of a resurrection body freed from all depletion &mdash; full, rich, and imperishable (1 Cor 15:42: &ldquo;sown in dishonor, raised in glory; sown in weakness, raised in power&rdquo;).</p>",
    "25": "<p>&ldquo;And another dies in bitterness of soul, having never tasted what is good.&rdquo; Christ died &ldquo;in bitterness of soul&rdquo; &mdash; Heb 12:2 (&ldquo;for the joy set before him he endured the cross, scorning its shame&rdquo;) implies the bitterness that preceded the joy. Yet his death that was bitter has made possible an outcome where believers &ldquo;taste that the Lord is good&rdquo; (1 Pet 2:3; Ps 34:8). The one who endured bitterness without tasting good has made eternal good available to all who had never tasted it.</p>",
    "26": "<p>A forward-pointer: &ldquo;they lie down together in the dust, and worms cover them both.&rdquo; The great death-equalizer is broken by resurrection. Christ lay in the dust of death (Ps 22:15: &ldquo;you lay me in the dust of death&rdquo;) and rose, becoming the firstfruits that guarantees the harvest: 1 Cor 15:20&ndash;22 (&ldquo;as in Adam all die, so in Christ all will be made alive&rdquo;). The worms that covered Job anticipate the corruption that Christ&rsquo;s resurrection body was not allowed to see (Acts 2:27,31; Ps 16:10).</p>",
    "27": "<p>&ldquo;I know your thoughts and the schemes you wrongfully contrive against me.&rdquo; Christ&rsquo;s omniscience &mdash; &ldquo;he knew what was in each person&rdquo; (John 2:25) &mdash; meant he knew the thoughts and schemes of those around him, yet continued with the redemptive plan. He knew Judas would betray him (John 6:70&ndash;71; 13:11,26&ndash;27) and loved him, served him at the Last Supper, called him &ldquo;friend&rdquo; even in the garden (Matt 26:50). Knowing the schemes did not stop his love.</p>",
    "28": "<p>&ldquo;For you say, &lsquo;Where is the house of the noble man? Where are the dwelling places of the wicked?&rsquo;&rdquo; The friends&rsquo; implied argument that the wicked always lose their houses is answered by Christ who &ldquo;has no place to lay his head&rdquo; (Matt 8:20) &mdash; the righteous man who was homeless while the wicked often dwell in comfort. His homelessness was not punishment but voluntary identification with the dispossessed, and his resurrection is the installation in &ldquo;the house of the LORD forever&rdquo; (Ps 23:6).</p>",
    "29": "<p>&ldquo;Have you not asked those who travel the roads?&rdquo; The appeal to universal testimony &mdash; the witnesses of common human experience &mdash; anticipates Peter&rsquo;s appeal at Pentecost: &ldquo;fellow Israelites, listen to this: Jesus of Nazareth was a man accredited by God to you by miracles, wonders and signs, which God did among you through him, <em>as you yourselves know</em>&rdquo; (Acts 2:22). The resurrection is supported by universal testimony: &ldquo;he appeared to more than five hundred of the brothers and sisters at the same time, most of whom are still living&rdquo; (1 Cor 15:6).</p>",
    "30": "<p>&ldquo;That the wicked is spared on the day of disaster and delivered through to the day of wrath.&rdquo; The wicked spared on the day of disaster is the condition Christ took upon himself: at Gethsemane, the disciples fled and were spared (fulfilling Zech 13:7, quoted Matt 26:31); Christ was not spared. He went through the day of wrath so that those who believe in him would be delivered from it: 1 Thess 1:10 (&ldquo;Jesus, who rescues us from the coming wrath&rdquo;).</p>",
    "31": "<p>&ldquo;Who will tell him to his face what he has done? Who will repay him for his deeds?&rdquo; The apparent immunity of the powerful wicked from face-to-face accountability is the present-age injustice. Christ, who never shirked face-to-face truth-telling (Matt 23:1&ndash;36: the woes to the Pharisees; John 8:44&ndash;45 to the crowds), promises to execute the final face-to-face accountability: Rev 20:12 (&ldquo;each person was judged according to what they had done&rdquo;). The one who told people the truth to their faces will ensure no one escapes the final accounting.</p>",
    "32": "<p>&ldquo;Yet he is borne to the grave, and a vigil is kept over his tomb.&rdquo; The honored burial of the apparently prosperous wicked is answered by the honored burial of Christ &mdash; in a new tomb, by Joseph of Arimathea, with Nicodemus bringing spices (John 19:38&ndash;42). The irony is that Christ, whom the authorities condemned, was buried with the honor typically reserved for royalty, and the vigil kept over his tomb (Matt 27:65&ndash;66) was overturned by resurrection.</p>",
    "33": "<p>&ldquo;The clods of the valley lie sweetly upon him; every person follows after him.&rdquo; The gentle burial and the long procession of those who have died before &mdash; every person eventually following &mdash; is the universal human experience of death. Christ entered this universal procession (Heb 2:14: &ldquo;since the children have flesh and blood, he too shared in their humanity&rdquo;) but reversed it: he is the last in the procession to die and the first to rise, and all who follow him in death will follow him in resurrection (1 Thess 4:14: &ldquo;God will bring with Jesus those who have fallen asleep in him&rdquo;).</p>",
    "34": "<p>&ldquo;How then do you comfort me with empty words, when nothing but falsehood remains in your answers?&rdquo; Job&rsquo;s devastating verdict on the friends&rsquo; comfort is confirmed by YHWH in 42:7 (&ldquo;you have not spoken of me what is right, as my servant Job has&rdquo;). Christ is the true Comforter who replaces empty words: &ldquo;the Advocate, the Holy Spirit, whom the Father will send in my name, will teach you all things and will remind you of everything I have said to you&rdquo; (John 14:26). The empty comfort of human theology gives way to the substantive comfort of the Paraclete sent by the risen Christ.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', 'job')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', 'job', c)
    total = sum(len(vs) for vs in CHRIST.values())
    print(f'job mkt-christ: {total} entries written (ch19-21)')

if __name__ == '__main__':
    main()
